26	const PROCESSING_FEE = 5;
27	const FIRST_INSURANCE_RATE = 0.1;
28	
29	const BASE_PREMIUM: Record<string, number> = {
30	  sword: 100,
31	  amulet: 60,
32	  staff: 80,
33	  potion: 40,
34	  rune: 25,
35	};
36	
37	const premiumForItem = (item: Item): number => {
38	  const base = BASE_PREMIUM[item.type];
39	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
40	  return base + firstInsuranceSurcharge;
41	};
42	
43	export const quote = (
44	  _customer: Customer,
45	  items: Item[],
46	  _priorContracts: number,
47	): number => {
48	  const itemsTotal = items.reduce((sum, item) => sum + premiumForItem(item), 0);
49	  return itemsTotal + PROCESSING_FEE;
50	};
51	
52	export const claim = (
53	  _policy: Policy,
54	  _incident: Incident,
55	): { payout: number; remainingCap: number } => {
56	  return undefined as unknown as { payout: number; remainingCap: number };
57	};
