62	describe("MHPCO Claim Office — claim", () => {
63	  // Standard reimbursement (no special clauses)
64	  it.todo("regular steel sword ench 3, damage 500 → payout 400 (500 − 100 deductible)");
65	  it.todo("rune (no enchantment / material), damage 200 → payout 100 (200 − 100 deductible)");
66	
67	  // Enchantment ≥8 clause
68	  it.todo("steel sword ench 9, damage 1000 → payout 400 (50% then deductible)");
69	
70	  // Dragon material clause
71	  it.todo("dragon-material sword ench 5, damage 800 → payout 700 (full, then deductible)");
72	
73	  // Both clauses — 50% wins, then deductible
74	  it.todo("dragon-material sword ench 9, damage 1000 → payout 400");
75	  it.todo("dragon-material sword ench exactly 8, damage 1000 → payout 400 (high-ench applies, then deductible)");
76	
77	  // Deductible per damage event
78	  it.todo("dragon attack damaging sword 500 + amulet 300 → payout 600 (deductible per item)");
79	
80	  // Multiple items of same type
81	  it.todo("policy with two swords; damage to both → each treated as separate damage with own deductible");
82	  it.todo("damages array has more entries of a type than the policy covers → throws error");
83	
84	  // Cap exhaustion
85	  it.todo("policy: sword + amulet → insurance sum 1600, cap 3200");
86	  it.todo("policy: cursed sword → cap 2000 (based on unmodified insurance value)");
87	  it.todo("policy: sword + 3 runes (block) → insurance sum 1750 (block doesn't affect sum)");
88	  it.todo("sword (cap 2000), first claim 1500 → payout 1400, remaining 600; second claim 1500 → payout 600, remaining 0");
89	
90	  // Rounding for payouts
91	  it.todo("payout calculation yielding 350.5 → final payout 350 (rounded down)");
92	
93	  // Errors
94	  it.todo("claim references damage for an item not in the policy → throws error");
95	  it.todo("claim contains damage with negative amount → throws error");
96	});
